module RefModule (
    input clk,
    input sreset,
    input [5:0] reset_value,
    output [5:0] q );reg [5:0] unused_q_reg;

    always @(posedge clk) begin
        if (sreset)
            unused_q_reg <= reset_value;
        else
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
